	if err != nil {
		return nil, nil, err
	}

	out := make(chan bead.LifecycleEvent)
	go func() {
		defer close(out)
		for {
			select {
			case <-ctx.Done():
				return
			case evt, ok := <-events:
				if !ok {
					return
				}
				lifecycle := evt.ToLifecycleEvent()
				select {
				case out <- lifecycle:
				case <-ctx.Done():
					return
				}
			}
		}
	}()

	return out, cancel, nil
}

